x1, y1 = list(map(int, input().split()))
x2, y2 = list(map(int, input().split()))

d = 0

while x1 != x2 or y1 != y2:
    if abs(x1 - x2) >= 1 and abs(y1 - y2) >= 1:
        x1 += 1
        y1 += 1
        d += 1
    elif abs(x1 - x2) >= 1:
        x1 += 1
        d += 1
    elif abs(y1 - y2) >= 1:
        y1 += 1
        d += 1
    else:
        if x1 > x2:
            x1 -= 1
        elif x1 < x2:
            x1 += 1
        elif y1 > y2:
            y1 -= 1
        elif y1 < y2:
            y1 += 1
        d += 1

print(d)
